// Simple TypeScript function
function add(a: number, b: number): number {
    return a + b;
}

// Variable declarations
const message: string = "Hello, World!";
let count = 0;

// If statement
if (count < 10) {
    count++;
}

// While loop
while (count < 20) {
    count += 2;
}

